@media only screen and (max-width:768px) {
    #header {
        background: black;
        padding: 10px 10px;
        border: none;        
    }

    main#primary {
        padding-top:80px;
    }
}

@media only screen and (min-width:768px) {
	main#primary {
		padding-top: 100px;
	}
}

main#primary .entry-title {
    text-align: center;
    padding: 15px 0px 30px 0px;	
}
